  "answer": {
    "BFT_protocols": {
      "assumed_failure_model": "Byzantine faults: replicas may behave arbitrarily maliciously or incorrectly, including sending conflicting messages, lying, or deviating from the protocol.",
      "f": "The system tolerates up to f Byzantine replicas.",
      "minimum_replicas": "n >= 3f + 1.",
      "notes": "This is the standard textbook bound for Byzantine agreement/replication in the usual partially synchronous or synchronous settings with authenticated channels/signatures depending on the protocol. The 3f+1 bound is the key point; it does not come from crash faults. Omission faults are weaker than Byzantine faults, but BFT is typically stated for the stronger Byzantine model."
    },
    "Paxos_Raft": {
      "assumed_failure_model": "Crash/omission faults: replicas are assumed to fail by stopping (crash) or, in some formulations, by omitting messages, but not by acting maliciously or equivocating.",
      "f": "The system tolerates up to f crash-failed replicas.",
      "minimum_replicas": "n >= 2f + 1.",
      "notes": "This is the standard quorum-based bound for crash-tolerant consensus/replication. Paxos and Raft are commonly presented for asynchronous or partially synchronous networks; safety does not require synchrony, though liveness typically needs eventual synchrony and a stable leader/majority communication. The 2f+1 bound assumes crashes/omissions only, not Byzantine behavior."
    },
    "comparison_summary": "BFT assumes Byzantine behavior and needs 3f+1 replicas; Paxos/Raft assume crash/omission behavior and need 2f+1 replicas. If the failure model were strengthened from crash/omission to Byzantine, the replica requirement increases from 2f+1 to 3f+1. Synchrony affects liveness assumptions, but the stated quorum bounds are the standard textbook replica counts under their respective failure models."
  }
