{
  "comparison": {
    "consensus_problem": {
      "paxos": "Goal: reach agreement (consensus) on a single value among distributed participants in the presence of failures. In practice, Paxos is used to drive state machine replication (often via repeated rounds / Multi-Paxos) so the cluster agrees on the same sequence of commands/state transitions.",
      "raft": "Goal: achieve consensus on a replicated log—i.e., ensure all servers have the same log entries in the same order. Raft then applies the committed log entries to produce a replicated state machine; operationally, it provides results equivalent to multi-Paxos for log-based state machine replication."
    },
    "leadership_and_coordination": {
      "paxos": {
        "coordination_mechanism": "No single distinguished leader. Consensus is coordinated via roles such as proposer and acceptor using the Phase 1 (prepare/promise) and Phase 2 (accept) protocol with ballots/proposal numbers; learners learn the chosen value. Safety is guaranteed even with competing proposers through the ballot-number rules and quorums.",
        "leadership_established_changed": "There is no explicit leader election; effectively any proposer can initiate proposals. Progress (liveness) can be aided by choosing/using a particular leader-like proposer, but it’s not inherent to the algorithm. Conflicts are resolved by using higher-numbered ballots." 
      },
      "raft": {
        "coordination_mechanism": "Explicit leader-based design. A single leader coordinates replication by sending AppendEntries (heartbeats and log replication) to followers; the leader also drives commitment by ensuring entries are replicated to majorities.",
        "leadership_established_changed": "Leader election is explicit: servers start as followers; if they miss heartbeats within an election timeout they become candidates and request votes. A candidate becomes leader after receiving votes from a majority. Leadership changes when the current leader fails (detected by timeout) and a new election (higher term) elects a new leader."
      }
    },
    "quorum_and_majority_requirements": {
      "paxos": {
        "decision_safety_basis": "A chosen value is determined via acceptor quorums. Safety is ensured by requiring intersections between quorums across phases/rounds: typically a value is (safely) decided after being accepted by a majority of acceptors.",
        "majority_requirement": "For N acceptors, quorums are of size floor(N/2)+1 (a majority)."
      },
      "raft": {
        "commit_safety_basis": "A log entry is committed once it is replicated on a majority of servers (i.e., stored in the leader’s and in enough followers’ logs). This ensures safety because majorities intersect, so committed entries can’t be lost or reordered by a later leader.",
        "majority_requirement": "For N servers, a majority is floor(N/2)+1 (quorum size)."
      }
    }
  }
}

